-- ============================================================
-- DOMAIN TABLES
-- ============================================================

-- Core identity table
CREATE TABLE users (
    user_id INT PRIMARY KEY AUTO_INCREMENT COMMENT 'Unique user identifier',
    email VARCHAR(255) NOT NULL UNIQUE COMMENT 'User email (unique, encrypted at rest)',
    username VARCHAR(100) NOT NULL UNIQUE COMMENT 'Username for login',
    password_hash VARCHAR(255) NOT NULL COMMENT 'Argon2id hashed password',
    role_id INT NOT NULL COMMENT 'FK to roles table',
    is_active BOOLEAN DEFAULT TRUE COMMENT 'Soft delete via deleted_at',
    created_by INT COMMENT 'FK to users (audit)',
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP COMMENT 'Record creation time',
    updated_by INT COMMENT 'FK to users (audit)',
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Last modification time',
    deleted_by INT COMMENT 'FK to users (soft delete)',
    deleted_at TIMESTAMP NULL COMMENT 'Soft delete timestamp (NULL = active)',

    FOREIGN KEY (role_id) REFERENCES roles(role_id),
    FOREIGN KEY (created_by) REFERENCES users(user_id),
    FOREIGN KEY (updated_by) REFERENCES users(user_id),
    FOREIGN KEY (deleted_by) REFERENCES users(user_id),

    INDEX idx_email (email),
    INDEX idx_username (username),
    INDEX idx_role_id (role_id),
    INDEX idx_created_at (created_at),
    INDEX idx_is_active (is_active)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci
COMMENT='Core user table (3NF normalized, encrypted PII)';

-- Role-based access control
CREATE TABLE roles (
    role_id INT PRIMARY KEY AUTO_INCREMENT COMMENT 'Unique role identifier',
    role_name VARCHAR(50) NOT NULL UNIQUE COMMENT 'Role name (admin, user, guest)',
    description VARCHAR(500) COMMENT 'Role description',
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,

    INDEX idx_role_name (role_name)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
COMMENT='Roles for RBAC';

-- Permission mapping
CREATE TABLE role_permissions (
    role_id INT NOT NULL,
    permission_id INT NOT NULL,
    PRIMARY KEY (role_id, permission_id),
    FOREIGN KEY (role_id) REFERENCES roles(role_id) ON DELETE CASCADE,
    FOREIGN KEY (permission_id) REFERENCES permissions(permission_id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
COMMENT='N:M mapping between roles and permissions';

-- Permissions reference
CREATE TABLE permissions (
    permission_id INT PRIMARY KEY AUTO_INCREMENT,
    permission_name VARCHAR(50) NOT NULL UNIQUE COMMENT 'e.g. read, write, delete',
    description VARCHAR(500),
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ============================================================
-- AUDIT TABLES
-- ============================================================

-- Immutable audit trail (for compliance: GDPR, HIPAA, PCI-DSS)
CREATE TABLE user_audit (
    audit_id BIGINT PRIMARY KEY AUTO_INCREMENT COMMENT 'Unique audit entry',
    user_id INT NOT NULL COMMENT 'FK to users',
    action VARCHAR(50) NOT NULL COMMENT 'INSERT, UPDATE, DELETE',
    before_state JSON COMMENT 'Old values (for UPDATE)',
    after_state JSON COMMENT 'New values',
    changed_by INT COMMENT 'FK to users (who made change)',
    changed_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP COMMENT 'When change occurred',
    ip_address VARCHAR(45) COMMENT 'IPv4 or IPv6 of request',
    user_agent TEXT COMMENT 'Browser/app identifier',
    correlation_id VARCHAR(36) COMMENT 'Trace ID for distributed systems',

    FOREIGN KEY (user_id) REFERENCES users(user_id),
    FOREIGN KEY (changed_by) REFERENCES users(user_id),

    INDEX (user_id, changed_at),
    INDEX (changed_by, changed_at),
    INDEX (action)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4
COMMENT='Immutable audit trail (append-only, OWASP A09 compliant)';

-- ============================================================
-- CONSTRAINTS & CHECKS
-- ============================================================

-- Ensure valid role_id on insert (double-check)
ALTER TABLE users ADD CONSTRAINT chk_user_role
CHECK (role_id IS NOT NULL);

-- Ensure no null email
ALTER TABLE users ADD CONSTRAINT chk_user_email
CHECK (email IS NOT NULL);

-- ============================================================
-- TRIGGERS (Auto-audit on user changes)
-- ============================================================

-- Trigger: Log user INSERT
CREATE TRIGGER user_insert_audit AFTER INSERT ON users
FOR EACH ROW
BEGIN
    INSERT INTO user_audit (user_id, action, after_state, changed_by, changed_at)
    VALUES (NEW.user_id, 'INSERT',
            JSON_OBJECT('email', NEW.email, 'role_id', NEW.role_id),
            @current_user_id, NOW());
END;

-- Trigger: Log user UPDATE
CREATE TRIGGER user_update_audit AFTER UPDATE ON users
FOR EACH ROW
BEGIN
    IF OLD.email != NEW.email OR OLD.role_id != NEW.role_id OR OLD.is_active != NEW.is_active THEN
        INSERT INTO user_audit (user_id, action, before_state, after_state, changed_by)
        VALUES (NEW.user_id, 'UPDATE',
                JSON_OBJECT('email', OLD.email, 'role_id', OLD.role_id, 'is_active', OLD.is_active),
                JSON_OBJECT('email', NEW.email, 'role_id', NEW.role_id, 'is_active', NEW.is_active),
                @current_user_id);
    END IF;
END;

-- Trigger: Log user DELETE (soft delete on deleted_at)
CREATE TRIGGER user_delete_audit AFTER UPDATE ON users
FOR EACH ROW
WHEN (NEW.deleted_at IS NOT NULL AND OLD.deleted_at IS NULL)
BEGIN
    INSERT INTO user_audit (user_id, action, after_state, changed_by)
    VALUES (NEW.user_id, 'DELETE', JSON_OBJECT('deleted_at', NEW.deleted_at), NEW.deleted_by);
END;

